// api/quote.js — Vercel Serverless Function
// Generated by the quote-wizard skill and deployed with every Package 3 site.
// Receives the wizard form submission, sends a formatted HTML notification email
// via Resend to the tradesperson.
//
// Environment variables required in Vercel project settings:
//   RESEND_API_KEY  — FORGE's Resend API key
//   QUOTE_TO_EMAIL  — tradesperson's email address (set per client deployment)
//   BUSINESS_NAME   — client business name (set per client deployment)

export default async function handler(req, res) {
  // CORS headers — allow the wizard (same domain) to POST
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.status(200).end();
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });

  try {
    const {
      customerName,
      customerPhone,
      customerEmail,
      customerPostcode,
      services,       // string[] — selected service names
      description,    // string — free text description
      followups,      // {question: string, answer: string}[] — trade-specific answers
    } = req.body;

    const businessName = process.env.BUSINESS_NAME || 'Your Business';
    const toEmail      = process.env.QUOTE_TO_EMAIL;

    if (!toEmail) {
      console.error('QUOTE_TO_EMAIL not set');
      return res.status(500).json({ error: 'Routing not configured' });
    }

    const now = new Date().toLocaleString('en-GB', {
      weekday: 'long', day: 'numeric', month: 'long', year: 'numeric',
      hour: '2-digit', minute: '2-digit', timeZone: 'Europe/London',
    });

    const servicesHtml = (services || [])
      .map(s => `<li style="margin-bottom:6px;font-size:15px;">${s}</li>`)
      .join('');

    const followupsHtml = (followups || []).length
      ? (followups || []).map(f => `
          <tr>
            <td style="padding:7px 16px 7px 0;color:#666;font-size:14px;white-space:nowrap;vertical-align:top;">${f.question}</td>
            <td style="padding:7px 0;font-size:14px;color:#111;font-weight:600;">${f.answer}</td>
          </tr>`).join('')
      : '';

    const phoneClean = (customerPhone || '').replace(/\s/g, '');

    const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
</head>
<body style="margin:0;padding:0;background:#f2f2f2;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f2f2f2;padding:32px 16px;">
    <tr><td align="center">
      <table width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#ffffff;border-radius:10px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);">

        <!-- Header -->
        <tr><td style="background:#111111;padding:24px 32px;">
          <p style="margin:0 0 4px;color:#888;font-size:11px;text-transform:uppercase;letter-spacing:1.5px;">New Quote Request</p>
          <h1 style="margin:0 0 8px;color:#ffffff;font-size:24px;font-weight:700;line-height:1.2;">${businessName}</h1>
          <p style="margin:0;color:#666;font-size:13px;">${now}</p>
        </td></tr>

        <!-- Customer -->
        <tr><td style="padding:28px 32px 0;">
          <p style="margin:0 0 8px;font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#999;">Customer</p>
          <h2 style="margin:0 0 16px;font-size:22px;color:#111;font-weight:700;">${customerName}</h2>
          <table cellpadding="0" cellspacing="0">
            <tr>
              <td style="padding-right:12px;padding-bottom:10px;">
                <a href="tel:${phoneClean}"
                   style="display:inline-block;background:#e8f4ff;color:#0055cc;text-decoration:none;padding:10px 18px;border-radius:8px;font-size:15px;font-weight:600;border:1px solid #cce0ff;">
                  📞&nbsp; ${customerPhone}
                </a>
              </td>
              <td style="padding-bottom:10px;">
                <a href="mailto:${customerEmail}"
                   style="display:inline-block;background:#e8fff0;color:#006633;text-decoration:none;padding:10px 18px;border-radius:8px;font-size:15px;font-weight:600;border:1px solid #99ddb3;">
                  ✉️&nbsp; ${customerEmail}
                </a>
              </td>
            </tr>
          </table>
          ${customerPostcode ? `<p style="margin:4px 0 0;font-size:14px;"><a href="https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(customerPostcode)}" style="color:#555;text-decoration:none;">📍&nbsp; ${customerPostcode}</a></p>` : ''}
        </td></tr>

        <!-- Divider -->
        <tr><td style="padding:24px 32px 0;"><hr style="border:none;border-top:1px solid #eeeeee;margin:0;"></td></tr>

        <!-- Services -->
        <tr><td style="padding:24px 32px 0;">
          <p style="margin:0 0 10px;font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#999;">Services Requested</p>
          <ul style="margin:0;padding-left:20px;color:#111;line-height:1.8;">${servicesHtml}</ul>
        </td></tr>

        <!-- Description -->
        ${description ? `
        <tr><td style="padding:24px 32px 0;">
          <p style="margin:0 0 10px;font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#999;">Description</p>
          <p style="margin:0;background:#f8f8f8;border-left:3px solid #ddd;padding:14px 18px;color:#333;font-size:15px;line-height:1.7;border-radius:0 8px 8px 0;">${description}</p>
        </td></tr>` : ''}

        <!-- Follow-ups -->
        ${followupsHtml ? `
        <tr><td style="padding:24px 32px 0;">
          <p style="margin:0 0 10px;font-size:11px;text-transform:uppercase;letter-spacing:1.5px;color:#999;">Additional Details</p>
          <table cellpadding="0" cellspacing="0" width="100%" style="border-top:1px solid #eee;">
            ${followupsHtml}
          </table>
        </td></tr>` : ''}

        <!-- Photos note -->
        <tr><td style="padding:24px 32px;">
          <div style="background:#fff8e1;border:1px solid #ffe082;border-radius:8px;padding:14px 18px;">
            <p style="margin:0;color:#7a5700;font-size:14px;line-height:1.5;">
              📸&nbsp; <strong>Photos:</strong> The customer has been asked to send photos when you reply to their enquiry. Reply to this email or call them directly to request them.
            </p>
          </div>
        </td></tr>

        <!-- Footer -->
        <tr><td style="background:#f8f8f8;padding:16px 32px;border-top:1px solid #eeeeee;">
          <p style="margin:0;color:#aaa;font-size:12px;line-height:1.5;">
            Sent by FORGE &nbsp;·&nbsp; Replying to this email will go directly to ${customerName} at ${customerEmail}
          </p>
        </td></tr>

      </table>
    </td></tr>
  </table>
</body>
</html>`;

    const resendRes = await fetch('https://api.resend.com/emails', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${process.env.RESEND_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        from:     'FORGE Quotes <quotes@getforge.co.uk>',
        to:       [toEmail],
        reply_to: customerEmail,
        subject:  `New Quote — ${(services || [])[0] || 'Enquiry'} — ${customerName}`,
        html,
      }),
    });

    if (!resendRes.ok) {
      const err = await resendRes.text();
      console.error('Resend error:', err);
      return res.status(500).json({ error: 'Email failed' });
    }

    return res.status(200).json({ ok: true });

  } catch (err) {
    console.error(err);
    return res.status(500).json({ error: 'Server error' });
  }
}
